use embedded_graphics::pixelcolor::Rgb565;

#[derive(Clone, Copy)]
pub enum SpritePixel {
    Color(Rgb565),
    Transparent,
}

pub type Sprite = [SpritePixel; 256];

#[allow(non_snake_case)]
#[inline(always)]
pub const fn C(r: u8, g: u8, b: u8) -> SpritePixel {
    SpritePixel::Color(Rgb565::new(r, g, b))
}

pub const TRANSPARENT: SpritePixel = SpritePixel::Transparent;

pub const SPRITE_SCALE: i32 = 6;

#[inline]
pub fn blit_sprite_column(
    sprite: &Sprite,
    col_buf: &mut [Rgb565],
    screen_x: i32,
    screen_y: i32,
    cur_col: i32,
) {
    let sprite_col = (cur_col - screen_x) / SPRITE_SCALE;
    if sprite_col < 0 || sprite_col >= 16 {
        return;
    }

    for sprite_row in 0..16_i32 {
        let pixel = sprite[(sprite_row * 16 + sprite_col) as usize];
        if let SpritePixel::Color(color) = pixel {
            let row_start = screen_y + sprite_row * SPRITE_SCALE;
            for dy in 0..SPRITE_SCALE {
                let screen_row = row_start + dy;
                if screen_row >= 0 && (screen_row as usize) < col_buf.len() {
                    col_buf[screen_row as usize] = color;
                }
            }
        }
    }
}
